-- ======================== Task status history (MOBAPP Board 1) ========================
-- Используем хэш от id задачи для разнообразия длительностей переходов.
-- Формула: время в колонке = base_hours + (hash % variation_hours)
-- Все задачи проходят ВСЕ колонки по порядку: Бэклог спринта → В работе → На проверке → Выполнено

-- MOBAPP COMPLETED tasks (column_id = d0010000-0000-0000-0001-000000000004)
-- Этап 1: Бэклог спринта (от 2 до 18 часов)
INSERT INTO task_status_history (id, task_id, column_id, entered_at, left_at)
SELECT
    gen_random_uuid(),
    t.id,
    'd0010000-0000-0000-0001-000000000001',
    t.created_at,
    t.created_at + make_interval(hours => 2 + (abs(hashtext(t.id::text)) % 16))
FROM tasks t
WHERE t.project_id = 'c0000000-0000-0000-0001-000000000000'
  AND t.board_id = 'd0000000-0000-0000-0001-000000000001'
  AND t.column_id = 'd0010000-0000-0000-0001-000000000004';

-- Этап 2: В работе (от 1 до 7 дней — основная работа)
INSERT INTO task_status_history (id, task_id, column_id, entered_at, left_at)
SELECT
    gen_random_uuid(),
    t.id,
    'd0010000-0000-0000-0001-000000000002',
    t.created_at + make_interval(hours => 2 + (abs(hashtext(t.id::text)) % 16)),
    t.created_at + make_interval(hours => 2 + (abs(hashtext(t.id::text)) % 16))
                 + make_interval(hours => 24 + (abs(hashtext(t.id::text || 'work')) % 144))
FROM tasks t
WHERE t.project_id = 'c0000000-0000-0000-0001-000000000000'
  AND t.board_id = 'd0000000-0000-0000-0001-000000000001'
  AND t.column_id = 'd0010000-0000-0000-0001-000000000004';

-- Этап 3: На проверке (от 4 до 48 часов)
INSERT INTO task_status_history (id, task_id, column_id, entered_at, left_at)
SELECT
    gen_random_uuid(),
    t.id,
    'd0010000-0000-0000-0001-000000000003',
    t.created_at + make_interval(hours => 2 + (abs(hashtext(t.id::text)) % 16))
                 + make_interval(hours => 24 + (abs(hashtext(t.id::text || 'work')) % 144)),
    t.created_at + make_interval(hours => 2 + (abs(hashtext(t.id::text)) % 16))
                 + make_interval(hours => 24 + (abs(hashtext(t.id::text || 'work')) % 144))
                 + make_interval(hours => 4 + (abs(hashtext(t.id::text || 'review')) % 44))
FROM tasks t
WHERE t.project_id = 'c0000000-0000-0000-0001-000000000000'
  AND t.board_id = 'd0000000-0000-0000-0001-000000000001'
  AND t.column_id = 'd0010000-0000-0000-0001-000000000004';

-- Этап 4: Выполнено (entered_at, left_at = NULL — текущая колонка)
INSERT INTO task_status_history (id, task_id, column_id, entered_at, left_at)
SELECT
    gen_random_uuid(),
    t.id,
    'd0010000-0000-0000-0001-000000000004',
    t.created_at + make_interval(hours => 2 + (abs(hashtext(t.id::text)) % 16))
                 + make_interval(hours => 24 + (abs(hashtext(t.id::text || 'work')) % 144))
                 + make_interval(hours => 4 + (abs(hashtext(t.id::text || 'review')) % 44)),
    NULL
FROM tasks t
WHERE t.project_id = 'c0000000-0000-0000-0001-000000000000'
  AND t.board_id = 'd0000000-0000-0000-0001-000000000001'
  AND t.column_id = 'd0010000-0000-0000-0001-000000000004';

