-- Рабочие дни для генерации встреч
CREATE TEMP TABLE _workdays AS
SELECT d::date AS wd
FROM generate_series('2026-02-17'::date, '2026-05-08'::date, '1 day'::interval) d
WHERE EXTRACT(DOW FROM d) BETWEEN 1 AND 5;

-- MOBAPP daily scrum (Mon-Fri, 10:00-10:15)
INSERT INTO meetings (id, project_id, name, description, meeting_type, start_time, end_time, created_by, status)
SELECT
    ('a5000000-0000-0000-0001-' || lpad(row_number() OVER (ORDER BY wd)::text, 12, '0'))::uuid,
    'c0000000-0000-0000-0001-000000000000'::uuid,
    'Daily Scrum',
    'Ежедневная встреча команды мобильного приложения',
    'daily',
    (wd + TIME '10:00')::timestamptz,
    (wd + TIME '10:15')::timestamptz,
    'b0000000-0000-0000-0000-000000000001'::uuid,
    'active'
FROM _workdays;

