-- PORTAL weekly sync (every Wednesday 11:00-12:00)
INSERT INTO meetings (id, project_id, name, description, meeting_type, start_time, end_time, created_by, status)
SELECT
    ('a5000000-0000-0000-0002-' || lpad(row_number() OVER (ORDER BY wd)::text, 12, '0'))::uuid,
    'c0000000-0000-0000-0002-000000000000'::uuid,
    'Еженедельный синк',
    'Синхронизация команды портала',
    'sync',
    (wd + TIME '11:00')::timestamptz,
    (wd + TIME '12:00')::timestamptz,
    'b0000000-0000-0000-0000-000000000013'::uuid,
    'active'
FROM _workdays
WHERE EXTRACT(DOW FROM wd) = 3;

