-- ======================== Notification settings ========================

INSERT INTO notification_settings (user_id, event_type, in_system, in_email)
SELECT u.id, et.event_type, true, false
FROM users u
CROSS JOIN (VALUES
    ('task_assigned'),
    ('comment_mention'),
    ('task_status_change_author'),
    ('task_status_change_assignee'),
    ('task_status_change_watcher'),
    ('meeting_invite'),
    ('meeting_change'),
    ('meeting_cancel')
) AS et(event_type);

